The Snowflake provider (Snowflake-Labs/snowflake) lets you manage warehouses, databases, schemas, roles, grants, and users as code.

Provider setup:
```hcl
terraform {
  required_providers {
    snowflake = {
      source  = "Snowflake-Labs/snowflake"
      version = "~> 0.87"
    }
  }
}

provider "snowflake" {
  account  = var.snowflake_account
  username = var.snowflake_username
  # Use key pair auth, not password:
  private_key_path = "~/.ssh/snowflake_rsa_key.p8"
  role             = "SYSADMIN"
}
```

Managing core DE resources:
```hcl
resource "snowflake_warehouse" "transform" {
  name           = "TRANSFORM_WH"
  warehouse_size = "MEDIUM"
  auto_suspend   = 60    # suspend after 60s idle
  auto_resume    = true
  initially_suspended = true
}

resource "snowflake_database" "analytics" {
  name = "ANALYTICS"
}

resource "snowflake_schema" "marts" {
  database = snowflake_database.analytics.name
  name     = "MARTS"
}

resource "snowflake_role" "dbt_role" {
  name = "DBT_ROLE"
}

resource "snowflake_grant_privileges_to_role" "dbt_schema" {
  role_name  = snowflake_role.dbt_role.name
  privileges = ["USAGE", "CREATE TABLE", "CREATE VIEW"]
  on_schema {
    schema_name = "\"${snowflake_database.analytics.name}\".\"${snowflake_schema.marts.name}\""
  }
}
```

DE use case: provision dbt service account, warehouse, and RBAC permissions reproducibly across environments.
